var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 숲은 옛날 그대로네.","JPN":"この森は昔のままね。","ENG":"This forest looks just like it used to.","TWN":"這片樹林還是老樣子呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기억나. 어릴 때는 다른 아이들과 놀러 다니면서 여기저기에 별명을 붙여 주곤 했지.","JPN":"思い出すわ。子供の頃は他の子たちと一緒に遊びながら、色んな場所に名前を付けたっけ。","ENG":"I remember. I would run around the forest with other kids, and give nicknames to everything.","TWN":"我記得，小時候和其他小朋友一起玩耍時，還給它們一個個取了名字。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 바위는 뾰족해서 송곳 바위, 저 나무는 휘어져 있어서 할머니 나무. 그리고......","JPN":"この岩は尖ってるから「とんがり岩」、あの木は曲がってるから「おばあちゃんの木」。それから……","ENG":"This pointy rock was called the Ice Pick, and that bent tree, the Grandma Tree. And...","TWN":"這塊石頭很尖，所以叫錐子石，那棵樹是彎的，所以叫老奶奶樹，還有……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......학회의 상징. ","JPN":"……学会の象徴。 ","ENG":"The symbol of the Society. ","TWN":"……學會的象徵。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"요즘도 이런 걸 걸어 놓는구나.","JPN":"今でもこんなものを掛けておくのね。","ENG":"I'm surprised they're still hanging this thing.","TWN":"現在也掛著這種東西啊。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 앞으로는 더 볼 일 없겠지만.","JPN":"まあ、もう二度と目にすることは無いでしょうけれど。","ENG":"Well, I guess this will be the last time I see it again.","TWN":"嗯，雖然以後應該再也看不到了。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데...... 좀 이상하네.","JPN":"でも……何だかおかしいわね。","ENG":"But it's strange.","TWN":"不過……有些奇怪呢。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"옛날에도 이렇게 기분 나쁘게 생겼었나......?","JPN":"昔からこんなに不気味だったかしら……？","ENG":"Did it look this creepy back in the day?","TWN":"這以前看起來有這麼不舒服嗎……？"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEVI_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>지역 정보를 확인할 수 없습니다. 단말기를 초기화한 뒤 다시 시도해 주십시오.</color>","JPN":"<color=#ffd34c>地域情報を確認できません。端末を初期化してからもう一度ご確認ください。</color>","ENG":"<color=#ffd34c>Location check failed. Please reset your device and try again.</color>","TWN":"<color=#ffd34c>無法確認地區情報。請將裝置初始化後重新嘗試。</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐야. 최신형이라고 해서 샀더니.","JPN":"おかしいわね、最新型だって言うから買ったのに。","ENG":"Huh? This is supposed to be the latest model.","TWN":"什麼啊，聽說這是最新型號所以才買的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"벌써 고장일 리는 없고...... 촌구석이라 통신 상태가 안 좋나?","JPN":"こんなに早く壊れるはずはないし……田舎だから通信状態が悪いのかしら？","ENG":"Is it broken already? Maybe the reception is bad, being so far away from the city.","TWN":"不可能這就出故障了吧……是因為太偏僻了，所以信號才不好的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......응? 또 걸려 있잖아?","JPN":"……あら？　また掛けてある……","ENG":"Huh? There's the symbol again.","TWN":"……嗯？又中斷了？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"희한하네. 흠집이 난 곳까지 처음 봤던 거랑 똑같이 생겼어.","JPN":"変ね。傷のある場所まで、さっき見たのと全く同じだわ。","ENG":"That's odd. This symbol looks just like the one I saw before, even the scratches on it.","TWN":"奇怪了，連有痕跡的地方都和第一次看到的一模一樣。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러고 보니...... 주변 풍경도 비슷하네.","JPN":"そういえば……周りの風景もよく似てる。","ENG":"And now that I think of it, all my surroundings look the same.","TWN":"這麼說來……周圍的風景也很像。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마...... 같은 자리로 돌아온 건 아니겠지?","JPN":"まさか……同じ場所に戻って来たわけではないわよね？","ENG":"No, I'm not walking in circles now, am I?","TWN":"該不會……是回到同樣的地方了？"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......후훗. 나도 참. 남들이 들으면 웃을 소리나 하고.","JPN":"……ふふっ、私ったら。人に聞かれたら笑われちゃうわ。","ENG":"Heh. Listen to yourself, Regina. It's lucky that no one was around to hear that.","TWN":"……呵呵，我還真是，被別人聽見了會被嘲笑吧。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"숲은 어딜 가나 비슷해 보이니까. 먼 길을 오느라 피곤해진 거겠지.","JPN":"森はどこでも同じように見えるものだし。長旅に疲れたせいね。","ENG":"Everything looks the same when I'm in a forest. I must be tired from the long journey.","TWN":"因為在樹林中，景色無論在哪裡都很像，而且走了這麼遠，應該是我累了吧。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......착각이 아니었어.","JPN":"……勘違いじゃなかった。","ENG":"I wasn't just imagining things.","TWN":"……看來不是我的錯覺。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이건 송곳 바위, 저건 할머니 나무......","JPN":"これはとんがり岩、あれはおばあちゃんの木……","ENG":"That's the Ice Pick, and that's the Grandma Tree.","TWN":"這是錐子石，那是老奶奶樹……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 같은 길을 몇 번이나 맴돌고 있었다고? 대체 어떻게?","JPN":"じゃあ、同じ場所をぐるぐる回っていたということ？　どうして？","ENG":"I have been walking in circles all along. How is this even possible?","TWN":"那我就是一直在同一條路上繞了？到底怎麼回事？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"날도 어두워져 가는데...... 이러면 경찰에 연락할 수밖에 없나......?","JPN":"もう日も暮れそうなのに……警察に連絡するしかないかしら……？","ENG":"It's getting dark now. Maybe I should call the police.","TWN":"天色也漸漸暗下來了……這樣就只能請警察幫忙了吧……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"네. 신고 접수하겠습니다.","JPN":"はい、警察です。どうしましたか？","ENG":"Emergency Services. Please state the nature of your emergency.","TWN":"是，您的報案被受理了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"숲에서 길을 잃었습니다. 혹시 그쪽에서 위치 추적이 가능한가요?","JPN":"森で道に迷ってしまいました。そちらで位置追跡はできますか？","ENG":"I'm lost in a forest. Can you track my location?","TWN":"我在樹林裡迷路了，不知道你們那邊能追蹤到我的位置嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"네. <color=#ff3636>신</color> 고접수하 <color=#ff3636>겠습</color>니다.","JPN":"はい、<color=#ff3636>警</color> 察です。どう<color=#ff3636>しまし</color>たか？","ENG":"Emergency Services. <color=#ff3636>Pl</color>ease state the nature of your emer<color=#ff3636>gency</color>.","TWN":"是。<color=#ff3636>您的報案</color>被<color=#ff3636>受理</color>了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"방금 얘기했잖아요. 맥크레디 영지에 딸려 있는 숲입니다. 이름은 따로 없어요.","JPN":"今、お話ししたはずですが……マクレディー領の森です。地域の名前は特にありませんわ。","ENG":"I just told you. I'm in the forest inside the MacCready Estate. It doesn't have a name.","TWN":"剛才不是說了嗎？麥克蕾蒂領地上的一片森林，並沒有什麼名字。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"네. <color=#ff3636>신고접수하</color> 겠습니<color=#ff3636>다</color>.","JPN":"はい、<color=#ff3636>警察で</color> す。どうしま<color=#ff3636>したか</color>？","ENG":"Emergency Services. <color=#ff3636>Please sta</color>te the nature of your emergen<color=#ff3636>cy</color>.","TWN":"是。<color=#ff3636>您的報案</color>被<color=#ff3636>受理</color>了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"여보세요? 당신 뭐 하는 사람이죠? 다른 분 좀 바꿔 주시겠어요?","JPN":"もしもし？　あなたはどなたです？　他の方に代わっていただけませんか？","ENG":"Hello? Is this some kind of a joke? Can I speak to someone else, please?","TWN":"喂？你是在幹什麼啊？可以換其他人接一下嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"끊어졌네......","JPN":"切れた……","ENG":"They hung up...","TWN":"被掛斷了……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이젠 신호도 아예 안 잡히잖아. 어떻게 된 거람.","JPN":"もう電波も入らないわね。どういうことなのかしら……","ENG":"And now there's no signal. What on earth is happening?","TWN":"現在連信號都收不到了，怎麼辦呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 소리는......? 설마 사람?","JPN":"この音は……？　もしや、人？","ENG":"What's that sound? A person?","TWN":"這聲音是……？難道有人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이봐요! 거기 누구 있나요?! 도움이 필요해요!","JPN":"すみません！　どなたかいらっしゃいませんか！？　助けてください！","ENG":"Hey! Anybody there? Please help me!","TWN":"喂！有誰在那裡嗎？我需要幫助！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저, 저건 침식체......? 어째서 이런 곳에?","JPN":"あ、あれは侵食体……？　どうして、こんなところに？","ENG":"Th-that's a C.O.! What's that doing in a place like this?","TWN":"這、這是侵蝕體……？怎麼會在這種地方？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"아, 거기 산책 나온 곱상한 언니!","JPN":"ねえ、そこの散歩中のきれいなお姉さん！","ENG":"Hey there, pretty lady on a walk!","TWN":"啊，那邊出來散步的漂亮姐姐！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"빨랑빨랑 유턴해서 돌아가라구~ 안 그럼 쟤들한테 인생 과속 했다고 명줄 떼인다?","JPN":"さっさとUターンして帰った方がいいよ～。あの子たちに寿命縮められたくなかったらね～。","ENG":"Make a U-turn and drive home, or they'll give you a death ticket for speeding!","TWN":"趕快掉頭離開吧~不然它們就會追妳，要了妳的命啦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 말인지 하나도 못 알아듣겠어요! 좀 이해할 수 있게 말씀하세요!","JPN":"何をおっしゃっているのか、全く意味が分かりませんわ！\\n分かるように話してください！","ENG":"I didn't understand a single word you just said. Can you say that again, but this time like a normal person, please?","TWN":"完全聽不懂妳在說什麼！能說點人話嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"죽기 싫으면 냉큼 내빼라구, 이 아가씨야!","JPN":"死にたくなかったらさっさと逃げろって言ってるの！","ENG":"Run, or you'll die, silly!","TWN":"不想死的話就快逃，小姐！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어딜......!","JPN":"無礼な……！","ENG":"Not a chance!","TWN":"在哪……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"오우, 보기랑 다르게 시원시원하네?","JPN":"何だ、意外と強気だね。","ENG":"Ooh, this lady has some tricks up her sleeve.","TWN":"哦，與外表不同，性格很爽快嘛？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 땅은 저희 가문의 영지! 침식체들이 짓밟게 내버려 둘 수는 없습니다!","JPN":"ここは当家の領地！　侵食体の好きにはさせませんわ！","ENG":"This land belongs to my family. I won't have those Corrupted Objects roaming it!","TWN":"這片土地是我家族的領地！不能放任這些侵蝕體隨意糟蹋！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실전 경험은 없지만 기초 전투 훈련 정도는 관리국에서 받았어요! 저도 싸우겠습니다!","JPN":"実戦経験はありませんが、基礎戦闘訓練なら管理局で受けました！　私も戦いますわ！","ENG":"Although I haven't been in a real fight, I did receive basic combat training in the Administration. I'll take you on!","TWN":"我雖然沒有實戰經驗，但卻有在管理局接受基礎的戰鬥訓練！我也要戰鬥！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"아하핫! 거들겠다는 사람 말릴 이유 없지!","JPN":"アハハッ！　そこまで言うなら止めないよ！","ENG":"Ah hah hah! Be my guest. I never say no to people offering help!","TWN":"啊哈哈！我沒有理由阻止想要幫忙的人吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_NULL_QM","text":{"KOREA":"그럼 어디 신나게 쏴 갈겨 보실까!","JPN":"じゃあ、思いっきり撃ちまくっちゃえ！","ENG":"Now, let's do some butt-kicking, shall we?","TWN":"那我們就開個幾槍，去嗨一下吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_QM","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};